-- Create "items" table
CREATE TABLE "items" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "deleted_at" timestamptz NULL, "name" character varying NOT NULL, "description" character varying NOT NULL, "topic_name" character varying NULL, PRIMARY KEY ("id"));
-- Create index "items_topic_name_key" to table: "items"
CREATE UNIQUE INDEX "items_topic_name_key" ON "items" ("topic_name");
-- Create "products" table
CREATE TABLE "products" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "app_id" character varying NOT NULL, "name" character varying NOT NULL, "description" character varying NOT NULL, "price" numeric NOT NULL, "currency" character varying NOT NULL DEFAULT 'KZT', "is_active" boolean NOT NULL DEFAULT true, "is_limited" boolean NOT NULL DEFAULT false, "limited_till" timestamptz NULL, "left" bigint NOT NULL DEFAULT 0, "is_unique" boolean NULL DEFAULT false, "unique_limit" bigint NOT NULL DEFAULT 0, "is_expiring" boolean NULL DEFAULT false, "expiring_time" timestamptz NULL, PRIMARY KEY ("id"));
-- Create "bundles" table
CREATE TABLE "bundles" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "deleted_at" timestamptz NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "amount" double precision NOT NULL DEFAULT 1, "item_id" bigint NOT NULL, "product_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "bundles_items_bundles" FOREIGN KEY ("item_id") REFERENCES "items" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "bundles_products_bundles" FOREIGN KEY ("product_id") REFERENCES "products" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- Create index "bundle_product_id_item_id" to table: "bundles"
CREATE INDEX "bundle_product_id_item_id" ON "bundles" ("product_id", "item_id") WHERE (deleted_at IS NULL);
-- Create "subscriptions" table
CREATE TABLE "subscriptions" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "user_id" bigint NOT NULL, "tenant_id" bigint NOT NULL, "app_id" character varying NOT NULL, "product_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "subscriptions_products_subscriptions" FOREIGN KEY ("product_id") REFERENCES "products" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- Create "invoices" table
CREATE TABLE "invoices" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "user_id" bigint NOT NULL, "tenant_id" bigint NOT NULL, "app_id" character varying NOT NULL, "amount" bigint NOT NULL, "price" numeric NOT NULL, "currency" character varying NOT NULL DEFAULT 'KZT', "status" character varying NOT NULL DEFAULT 'CREATED', "paid_at" timestamptz NULL, "paid_till" timestamptz NULL, "is_paid_at_processed" boolean NOT NULL DEFAULT false, "is_paid_till_processed" boolean NOT NULL DEFAULT false, "product_id" bigint NOT NULL, "subscription_id" bigint NULL, PRIMARY KEY ("id"), CONSTRAINT "invoices_products_invoices" FOREIGN KEY ("product_id") REFERENCES "products" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "invoices_subscriptions_invoices" FOREIGN KEY ("subscription_id") REFERENCES "subscriptions" ("id") ON UPDATE NO ACTION ON DELETE SET NULL);
